challenge.solution:
from abc import ABC, abstractmethod

class DataExporter(ABC):
    @abstractmethod
    def export(self, data):
        pass

class JSONExporter(DataExporter):
    def export(self, data):
        return f'JSON: {data}'

class CSVExporter(DataExporter):
    pass
